// ============================================================
//  4K+ KALİTE FİLTRESİ
// ============================================================
const QUALITY_PATTERNS = [
  /\b2160p\b/i, /\b4K\b/i, /\bUHD\b/i,
  /\bBluRay\b/i, /\bBlu-Ray\b/i,
  /\bBDRemux\b/i, /\bBD\.?Remux\b/i, /\bRemux\b/i, /\bBDRip\b/i,
  /\bHDR(10)?(\+)?\b/i, /\bDolby\.?Vision\b/i, /\bDV\b/, /\bIMAX\b/i,
];
function isHighQuality(title = "") {
  return QUALITY_PATTERNS.some((re) => re.test(title));
}

