builder.defineCatalogHandler(async ({ type, id, extra }) => {
  const keyword = (extra?.search || "").toLowerCase().trim();
  try {
    if (keyword) {
      let metas = [];
      for (const host of CINEMETA_HOSTS) {
        try {
          const res = await axios.get(
            `${host}/catalog/${type}/top/search=${encodeURIComponent(keyword)}.json`,
            { timeout: 10000, headers: { "User-Agent": "Mozilla/5.0" } }
          );
          if (res.data?.metas?.length) { metas = res.data.metas; break; }
        } catch { /* try next */ }
      }
      return { metas: metas.slice(0, 50) };
    }
    const idList = type === "movie" ? POPULAR_MOVIES : POPULAR_SERIES;
    const metas  = await Promise.all(idList.map(async (imdbId) => {
      const meta = await fetchMeta(type, imdbId);
      if (!meta) return null;
      return { id: imdbId, type, name: meta.name, poster: meta.poster, background: meta.background, description: meta.description, year: meta.year, imdbRating: meta.imdbRating };
    }));
    return { metas: metas.filter(Boolean) };
  } catch (err) {
    console.error("Catalog error:", err.message);
    return { metas: [] };
  }
});

builder.defineStreamHandler(async ({ type, id }) => {
  if (!RD_API_KEY) return { streams: [{ name: "⚠️ Hata", description: "RD_API_KEY tanımlanmamış.", url: "" }] };
  try {
    const all      = await fetchTorrentioStreams(type, id);
    const filtered = filterHighQuality(all);
    const streams  = filtered.map(formatStream).filter((s) => s.url);
    console.log(`[${id}] Toplam: ${all.length} | 4K+: ${filtered.length}`);
    return { streams: streams.slice(0, 20) };
  } catch (err) {
    console.error("Stream error:", err.message);
    return { streams: [] };
  }
});

