const addonInterface = builder.getInterface();

const server = http.createServer((req, res) => {
  if (req.url === "/" || req.url === "/configure" || req.url === "/index.html") {
    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
    res.end(LANDING_HTML);
    return;
  }
  // Diğer istekler addon'a git
  addonInterface.router(req, res);
});

server.listen(PORT, () => {
  console.log(`\n✅  RD 4K Ultra HD Addon çalışıyor`);
  console.log(`🌐  Landing : http://localhost:${PORT}/`);
  console.log(`📡  Manifest: http://localhost:${PORT}/manifest.json\n`);
});
